}}}i:17;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:27:"Matt: Democratizing the Web";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=42428";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:43:"http://ma.tt/2013/05/democratizing-the-web/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:254:"<p>Michelle Atagana from Memeburn <a href="http://memeburn.com/2013/05/matt-mullenweg-on-how-open-source-is-democratising-the-web/">posted an interview we did when I was in South Africa: Matt Mullenweg on how open source is democratising the web</a>.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sun, 26 May 2013 00:16:02 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:18;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:63:"WordPress.tv: Blaz Robar: Photoshop Best Practice for WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19317";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:80:"http://wordpress.tv/2013/05/24/blaz-robar-photoshop-best-practice-for-wordpress/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:682:"<div id="v-0xX1UfOo-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19317/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19317/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19317&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/24/blaz-robar-photoshop-best-practice-for-wordpress/"><img alt="Blaz Robar: Photoshop Best Practice for WordPress" src="http://videos.videopress.com/0xX1UfOo/video-9912757e57_scruberthumbnail_0.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 25 May 2013 00:58:17 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:19;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:50:"WPTavern: Co-Founder Of WordPress To Receive Award";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7110";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:102:"http://feedproxy.google.com/~r/WordpressTavern/~3/3e-WX8J1jOo/co-founder-of-wordpress-to-receive-award";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3706:"<p>WordPress co-founder <a href="http://mikelittle.org/" title="http://mikelittle.org/">Mike Little</a> will be given the <a href="http://www.sascon.co.uk/2013/05/unsung-internet-visionary-to-be-honoured-at-sascon/" title="http://www.sascon.co.uk/2013/05/unsung-internet-visionary-to-be-honoured-at-sascon/">outstanding contribution to digital media award</a> at Sascon6. Sascon is a conference in the UK dedicated to a national audience of senior level digital and marketing professionals both agency and in-house working in the public and private sector. While Matt Mullenweg has been the high profile, public face of WordPress, Mike Little has for the most part, stayed behind the scenes. </p>\n<p><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/MikeLittleComment.jpg" rel="thumbnail"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/MikeLittleComment.jpg?resize=560%2C183" alt="Mike Little Comment" class="aligncenter size-full wp-image-7111" /></a></p>\n<p>If you would like to see the birth of WordPress, you can <a href="http://ma.tt/2003/01/the-blogging-software-dilemma/">read the post</a> as well as <a href="http://ma.tt/2003/01/the-blogging-software-dilemma/#comment-445">the comment</a> that started it all. </p>\n<p>It&#8217;s not like Mike has been silent over the years. In fact, he&#8217;s conducted a number of interviews. Here are a couple of the ones I found. </p>\n<p><a href="http://www.prolificnorth.co.uk/2013/02/how-a-stockport-developer-helped-create-the-worlds-biggest-online-publishing-phenomenon-for-free/">How a Stockport developer helped create the world’s biggest online publishing phenomenon – for free</a></p>\n<p><a href="http://astrotalkuk.org/2010/07/11/wordcampuk-manchester-17-18-july-2010/">Video Interview of when both were in attendance at WordCamp UK Manchester July of 2010</a>. This was the interview with the famous quote by Matt, <em>I met a guy who said he met his wife because of WordPress, I told him wow, I haven&#8217;t used that plugin</em></p>\n<div class="aligncenter"><div id="v-krVIGT4c-1" class="video-player"><div><img alt="" src="http://i2.wp.com/videos.videopress.com/krVIGT4c/mullenweg_little_interview_dvd.original.jpg?resize=560%2C314" /></div><p class="robots-nocontent">You do not have sufficient <a rel="nofollow" href="http://www.gnu.org/philosophy/free-sw.html">freedom levels</a> to view this video. Support free software and upgrade.</p></div></div>\n<p><a href="http://wpmu.org/wordcamp-uk-interview-mike-little-wordpress-co-founder/" title="http://wpmu.org/wordcamp-uk-interview-mike-little-wordpress-co-founder/">WordCamp UK Interview: Mike Little, WordPress Co-Founder</a> &#8211; Another video interview, this time conducted by Siobhan McKeown in 2011. </p>\n<p>You can follow Mike on Twitter <a href="https://twitter.com/mikelittlezed1">@mikelittlezed1</a></p>\n<p>If you get the chance, make sure to congratulate Mike on his award and give him a well deserved thank you for helping to pioneer WordPress. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/lexnet-interviews-matt-mullenweg" rel="bookmark" title="Lexnet Interviews Matt Mullenweg">Lexnet Interviews Matt Mullenweg</a></li>\n<li><a href="http://www.wptavern.com/it-took-houston-four-years" rel="bookmark" title="It Took Houston Four Years">It Took Houston Four Years</a></li>\n<li><a href="http://www.wptavern.com/matt-mullenweg-video-biography-interview" rel="bookmark" title="Matt Mullenweg Video Biography Interview">Matt Mullenweg Video Biography Interview</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/3e-WX8J1jOo" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 24 May 2013 22:35:33 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:20;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:71:"WordPress.tv: Evan Mullins: From PSD to WordPress Theme: Under the Skin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19200";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:87:"http://wordpress.tv/2013/05/24/evan-mullins-from-psd-to-wordpress-theme-under-the-skin/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:691:"<div id="v-GR8OZBEe-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19200/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19200/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19200&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/24/evan-mullins-from-psd-to-wordpress-theme-under-the-skin/"><img alt="Evan Mullins: From PSD to WordPress Theme: Under the Skin" src="http://videos.videopress.com/GR8OZBEe/video-0b247f325d_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 24 May 2013 21:14:52 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:21;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:40:"WPTavern: Basic Comment Quicktags Plugin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7107";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:92:"http://feedproxy.google.com/~r/WordpressTavern/~3/NCjbxU9QpLc/basic-comment-quicktags-plugin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3996:"<p><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/BasicCommentQuicktags.jpg" rel="thumbnail"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/BasicCommentQuicktags.jpg?resize=187%2C83" alt="Basic Comment Quicktags" class="alignright size-full wp-image-7108" /></a>There are very few instances when I&#8217;m browsing WPTavern.com without being logged in as an administrator. Turns out, I should do that more often as I discovered that my Comment Quicktags Reloaded plugin was broken. I&#8217;ve used Comment Quicktags Reloaded since launching WPTavern.com because I believe that comment forms are a lot like forum threads. Users should have the ability to bold words and use other tags while composing their comment, similar to how you would write a reply in a forum thread. CQR was developed by <a href="http://www.asymptomatic.net/">Owen Winkler</a> who was an early WordPress enthusiast but has since gone on to be a part of <a href="https://habariproject.org/en/">The Habari Project</a>. While the supported version of WordPress only went up to 2.2, the plugin continued to work way past that into the 3.0 branch. Thus began my search for an alternative.</p>\n<p>This brings me to the <a href="http://wordpress.org/plugins/basic-comment-quicktags/">Basic Comment Quicktags</a> plugin authored by <a href="http://profiles.wordpress.org/ipstenu/">Mika Epstein (Ipstenu)</a> and <a href="http://profiles.wordpress.org/marcdk/">Marcdk</a> This plugin is very straight forward. Simply install it, turn it on via a checkbox in the Discussions page of WordPress and watch as the <strong>Bold, Italic, Link and Quote</strong> buttons appear above the comment form. If you&#8217;re wondering why more tags were not added, Mika explains:</p>\n<blockquote><p>After careful consideration, and a long review of my users, those are the only ones they ever use! If you have a reasonable argument why I should add in others, I&#8217;ll listen.</p></blockquote>\n<p>While I don&#8217;t use bbPress just yet, I&#8217;m happy to report that Basic Comment Quicktags does have bbPress support built-in but not BuddyPress. While writing this article, I began to wonder why WordPress doesn&#8217;t ship with these tags above the comment form out of the box? I don&#8217;t have the answer but I did discover that the next best thing is knowing that a <a href="http://codex.wordpress.org/Quicktags_API">Quicktags API</a> was created and then added to WordPress 3.3. I think that this type of functionality should be part of every theme by default. I mean, why not? Shouldn&#8217;t users be able to easily compose comments with some of the bells and whistles that post authors have in the back-end of WordPress?</p>\n<p>But then, we run into the issue of whether it should be a theme option, or a stand alone plugin? Using a plugin, themes can be replaced without any loss of quicktag functionality. If it&#8217;s built into the theme, then when the theme goes, so do the quicktags. That&#8217;s a topic for debate but it&#8217;s nice to know that this type of simple functionality is built right into core so nobody has to worry about depending on one particular Quicktag plugin anymore. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/please-adopt-this-plugin-comment-quicktags-reloaded" rel="bookmark" title="Please Adopt This Plugin &#8211; Comment Quicktags Reloaded">Please Adopt This Plugin &#8211; Comment Quicktags Reloaded</a></li>\n<li><a href="http://www.wptavern.com/basic-guide-on-creating-plugin-ui" rel="bookmark" title="Basic Guide On Creating Plugin UI">Basic Guide On Creating Plugin UI</a></li>\n<li><a href="http://www.wptavern.com/how-to-mimic-the-wptavern-commenting-system" rel="bookmark" title="How To Mimic The WPTavern Commenting System">How To Mimic The WPTavern Commenting System</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/NCjbxU9QpLc" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 24 May 2013 17:31:46 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:22;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:60:"WPTavern: WordPress Trivia For Your WordPress Birthday Party";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7104";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:112:"http://feedproxy.google.com/~r/WordpressTavern/~3/5aB1moacBW0/wordpress-trivia-for-your-wordpress-birthday-party";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2881:"<p>As we get closer to the 10th anniversary of WordPress, people have been asking me if I know of any WordPress trivia plugins or games that they could use for their 10th anniversary birthday party. While I don&#8217;t know of any plugins, there is a WordPress Jeopardy style website you can use that if nothing else, can help generate some trivia questions. It&#8217;s called <a href="http://www.wpgameshow.com/" title="http://www.wpgameshow.com/">WP Gameshow</a>. The concept was created by the organizers of WordCamp Detroit, 2011. When I originally <a href="http://www.wptavern.com/wordpress-gameshow-now-available-to-play-from-home">wrote about the site</a>, Anthony stated in the comments:</p>\n<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2011/11/wpgameshow.png" rel="thumbnail"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2011/11/wpgameshow.png?resize=560%2C301" alt="WordPress Game Show" class="aligncenter size-full wp-image-5884" /></a></p>\n<blockquote><p>I’m glad everyone is enjoying the game! It was a lot of fun performing it live and we really would like to see what others can do with the platform. So yes, we do plan on releasing a theme which will allow for you to create your own questions and such. No time on release, but it is in the works.</p></blockquote>\n<p>To this day, nothing has been released although the domain is still active, complete with a game board. I got in touch with Anthony to see if he has made any progress on releasing this as a theme or plugin. </p>\n<blockquote><p>This is one of those things that we never finished for release. I just sent an email to my friend who I worked on it with for the most recent version. As soon as I hear back from him, I&#8217;m going to take another run at it and see if it&#8217;s &#8220;good enough&#8221; for use and we&#8217;ll try to post a copy of it for download on the trivia site.</p>\n<p>I&#8217;ll let you know as soon as I hear back from him and have the opportunity to put it up for release.</p></blockquote>\n<p>Once I hear from  Anthony about a download link being established, I&#8217;ll pass the word along. Until then, you&#8217;ll have to use the actual WPGameshow website. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/wordpress-trivia-winners" rel="bookmark" title="WordPress Trivia Winners">WordPress Trivia Winners</a></li>\n<li><a href="http://www.wptavern.com/wordpress-gameshow-now-available-to-play-from-home" rel="bookmark" title="WordPress Gameshow Now Available To Play From Home">WordPress Gameshow Now Available To Play From Home</a></li>\n<li><a href="http://www.wptavern.com/wptavern-trivia-game" rel="bookmark" title="WPTavern Trivia Game">WPTavern Trivia Game</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/5aB1moacBW0" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 24 May 2013 14:49:27 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:23;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:29:"Matt: Automattic After-Market";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=42420";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:42:"http://ma.tt/2013/05/automattic-secondary/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:4509:"<p>One of the most striking shifts in entrepreneurship when I started <a href="http://automattic.com/">Automattic</a> seven years ago was the rise of the Founder Friendly VCs. The standard operating procedure at the time for VC-backed companies consisted of bringing in &#8220;adult supervision,&#8221; founders often taking largely-ceremonial roles like &#8220;chief architect&#8221; after the business had scaled to a certain point, aggressive financial terms around liquidation preferences, and a control structure that more often than not left founders with a minority say in the future of the company, especially if it went through rough patches. Folks like <a href="http://www.trueventures.com/">True Ventures</a> (who Automattic has always been intertwined with) appeared as iconoclasts because they came out saying that founders were the best ones to grow a company long-term and structuring their entire practice and way of investing around that idea. It seems non-controversial now, but it was like <a href="http://en.wikipedia.org/wiki/Electric_Dylan_controversy">Dylan going electric</a>. Still in spite of their philosophical innovations, many of these funds were structured in similar ways to the ones of old, with 7-10 year fund lifetimes, for example.</p>\n<p>Fast-forward to 2013 and there&#8217;s an even more founder-friendly class of investors rising, at least for companies that have made it past a certain exit velocity of growth and revenue. Most visibly pioneered by <a href="http://techcrunch.com/2009/05/26/mark-zuckerberg-and-yuri-milner-talk-about-facebooks-new-investment-video/">Yuri Milner and Facebook in 2009</a> there&#8217;s a breed of later-stage investors from largely financial backgrounds that come in with the ability to write checks larger than the <a href="http://www.nvca.org/index.php?Itemid=147">entire size of most VC funds</a> and a desire to align with founders so strong that they embrace things that even VCs from the founder-friendly cohort would balk at: forgoing board seats, assigning voting proxies to founders, taking very long term approaches to growth, and investing in (and seeking out!) companies outside of the California/New York bubble, from South Africa to Russia to Brazil. The most interesting thing to me about this new generation is how behind the scenes they are: forget about a blog or Twitter, most of these guys don&#8217;t even have websites for their firms. These are some of the smartest and most successful people you&#8217;ll ever meet and you&#8217;ll never hear about them&#8230; they like it that way. Asymmetric information is their core competitive advantage.</p>\n<p>Anyway, wanted to get in front of the news that will inevitably come out in the next week or two: there has been a large secondary transaction in Automattic stock, about $50M worth. &#8220;Secondary&#8221; means that it&#8217;s existing stockholders, like the earliest investors or employees, selling stock to another investor versus money going into the company (&#8220;primary&#8221;). It was led by Lee Fixel at Tiger Global, one of the behind-the-scenes quiet geniuses that has previously invested in SurveyMonkey, Facebook, LinkedIn, Palantir, Square, Warby Parker&#8230; Automattic is healthy, generating cash, and already growing as fast as it can so there&#8217;s no need for the company to raise money directly &#8212; we&#8217;re not capital constrained. The minority of stockholders that elected to participate are holding on to the vast majority of their shares. We&#8217;re building an independent company that&#8217;s going to be a growing part of the fabric of the web for many years to come, so allowing early investors to lock in some returns releases any short-term pressure there might be on the company for a liquidity event and allows us to focus fully on the long road ahead.</p>\n<p>As sometimes happens in with regulated financial things, I can&#8217;t answer every question about this, but will leave comments open. I hope to see some of you on Monday the 27th when I&#8217;ll <a href="http://www.meetup.com/WordPress/">be celebrating the 10th anniversary of WordPress alongside community members in over 500 cities</a>. Also <a href="http://toni.org/2013/05/24/tiger-invests-in-automattic/">check out Toni&#8217;s post about all of the above</a>. If you&#8217;re interested in living anywhere and working hard alongside people passionate about the same, <a href="http://automattic.com/work-with-us/">Automattic is always hiring</a>.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 24 May 2013 13:33:49 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:24;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:53:"WordPress.tv: Dre Armeda: WordPress End-User Security";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19213";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:72:"http://wordpress.tv/2013/05/23/dre-armeda-wordpress-end-user-security-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:658:"<div id="v-vr3FsXRo-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19213/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19213/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19213&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/23/dre-armeda-wordpress-end-user-security-2/"><img alt="Dre Armeda: WordPress End-User Security" src="http://videos.videopress.com/vr3FsXRo/video-a9b97dbc41_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 23 May 2013 19:23:03 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:25;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:57:"WPTavern: Alternatives For A Better Planet WordPress Feed";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7098";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:109:"http://feedproxy.google.com/~r/WordpressTavern/~3/kYC3RX7OiDg/alternatives-for-a-better-planet-wordpress-feed";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:5052:"<p>The <a href="http://planet.wordpress.org/">WordPress Planet</a> is a collection of WordPress centric websites that aggregate their content into one stream of information. In 2009, <a href="http://www.wptavern.com/is-it-time-to-refocus-the-dashboard-for-news">I proposed the idea</a> of refocusing the dashboard so that it presented more WordPress Centric content. While some sites have been added and removed from the official Planet WordPress feed over the years, the core issue remains. It&#8217;s not as great of a source of WordPress information as it could be. I always thought that instead of having all the content from an individuals site published to the planet feed, it would have made much more sense to only subscribe to their WordPress category.</p>\n<h2>Alternatives:</h2>\n<p>Disappointed in the official planet feed, I searched for other resources of information and one day, came across a site called <a href="http://planetwordpress.planetozh.com/">PlanetOzh</a>. PlanetOzh is just like Planet WordPress except it has more sites to aggregate content from and is maintained by Ozh. Sites are added and removed on a somewhat routine basis. However, I remember sending an email to Ozh one day after I went through each site he was aggregating content from and told him which ones I thought needed to be removed due to their lack of WordPress specific content or that the site appeared dead. It was a substantial list. From my observation, it looks like he has cleaned up the site so it&#8217;s much more relevant than it was a few years ago.</p>\n<p>Recently, the topic of the WordPress Planet was brought up again by <a href="http://wpmu.org/wordpress-planet-pants-problem/">James Farmer of WPMU</a> where he does bring up some valid points. I&#8217;m of the opinion that the more people who see great WordPress centric information, the better off everyone in the WordPress ecosystem will be. So I&#8217;m all for making the WordPress Planet a better place. However, the official <a href="http://planet.wordpress.org/">Planet WordPress</a> feed is maintained by one person, Matt Mullenweg. Considering just how busy he is, I can understand how maintaining the list of sites on the planet feed would be one of the last priorities on his list. I think some would agree that there are far more important things to be spending time and energy on with WordPress.org versus the planet feed.</p>\n<p><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/betterplanetlogo.jpg" rel="thumbnail"><img class="aligncenter size-full wp-image-7100" alt="A Better Planet" src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/betterplanetlogo.jpg?resize=408%2C207" /></a></p>\n<p>If you&#8217;re looking for more variety of content from different WordPress centric websites in your dashboard, you should try the brand new plugin called <a href="http://wordpress.org/plugins/a-better-planet/">A Better Planet</a> by <a href="http://wplift.com/a-better-planet">WPLIft</a>. In a nutshell, this plugin is a more up-to-date and relevant version of the official planet WordPress feed. While the master list is controlled by one person, it looks like it&#8217;s a lot easier to have a WordPress site added to their list than the official feed.</p>\n<h2>Responsibility:</h2>\n<p>While I wouldn&#8217;t mind seeing other WordPress centric sites in the dashboard supplying great information to users all across the world, I also wouldn&#8217;t want to see those same sites treating the dashboard as an enormous, untapped customer base. Being in the WordPress dashboard comes with great responsibility. For example, you have to be on-board with the 100% GPL philosophy. Sites can not link to other sites that promote non-GPL products. Sites can not advertise non-GPL products through display ads or otherwise. It really boils down to being an excellent steward in the community. There are WordPress centric sites that meet that criteria but I don&#8217;t make the decision on who is added to the feed and who is not.</p>\n<h2>Discussion Points:</h2>\n<p>So considering we&#8217;ve been having this conversation for a few years now, has anything really changed? Do you even use the news widgets in the dashboard or do you hide them as soon as you can?</p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/is-it-time-to-refocus-the-dashboard-for-news" rel="bookmark" title="Is It Time To Refocus The Dashboard For News?">Is It Time To Refocus The Dashboard For News?</a></li>\n<li><a href="http://www.wptavern.com/99-different-wordpress-related-websites-to-watch" rel="bookmark" title="99 Different WordPress Related Websites To Watch">99 Different WordPress Related Websites To Watch</a></li>\n<li><a href="http://www.wptavern.com/hello-to-those-reading-from-the-dashboard" rel="bookmark" title="Hello To Those Reading From The Dashboard">Hello To Those Reading From The Dashboard</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/kYC3RX7OiDg" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 23 May 2013 18:46:35 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:26;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:43:"WPTavern: Review – Swiftype Search Plugin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7085";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:91:"http://feedproxy.google.com/~r/WordpressTavern/~3/i4oANGpafnI/review-swiftype-search-plugin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:6883:"<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/swiftypelogo.jpg" rel="thumbnail"><img class="alignright size-full wp-image-7086" alt="Swift Type Logo" src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/swiftypelogo.jpg?resize=153%2C49" /></a>In my journey of locating a <a href="http://www.wptavern.com/searching-for-a-better-wordpress-search">better WordPress search alternative</a>, it was suggested that I give <a href="https://swiftype.com/home">Swiftype</a> a try. <a href="https://swiftype.com/">Swiftype</a> is another search service that offloads the searching process to their servers instead of having to rely on the database to give results. Unlike my struggles with the <a href="http://www.wptavern.com/review-of-wp-elasticsearch-plugin">ElasticSearch Plugin</a>, the folks over at Swiftype couldn&#8217;t have made it any easier to get their plugin up and running.</p>\n<p>After signing up, I viewed their demo video which does a great job of explaining how to install and configure their WordPress plugin.</p>\n<div class="aligncenter"></div>\n<p>Their <a href="https://swiftype.com/pricing">plans</a> range from Hobbyist at $19.00 per month to a Custom Enterprise solution. They don&#8217;t list what comes with the free account but you can find out that information after you sign up. The free account is perfect for small websites that have less than 2,000 articles. As I&#8217;ve learned in this process of reviewing search services, an article, post, or  page is called a document.</p>\n<blockquote><p>One search engine, 2 domains, 2,000 documents, and 50 query customizations. Recrawl once a week. Your search results must display Swiftype branding.</p></blockquote>\n<p>Swiftype doesn&#8217;t enable users to search by categories or dates. However, I&#8217;m beginning to think that if the search results are relevant enough, there isn&#8217;t a need to include those search queries. One of the cool things about Swiftype is that they give you access to manipulate the search results so that if they are not relevant enough, you can take a result and place it higher on the list.</p>\n<div id="attachment_7089" class="wp-caption aligncenter"><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/ManipulateSearchResults.jpg" rel="thumbnail"><img class="size-full wp-image-7089" alt="Manipulate Search Results" src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/ManipulateSearchResults.jpg?resize=539%2C257" /></a><p class="wp-caption-text">I can help make the results more relevant</p></div>\n<p>One of my favorite features is the drop-down suggested search results. In my experimental use, I&#8217;ve noticed that most of the time, the results of what I&#8217;m searching for end up in the suggested results drop down box.</p>\n<p><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/SuggestedSearches.jpg" rel="thumbnail"><img class="aligncenter size-full wp-image-7090" alt="Suggest Searches" src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/SuggestedSearches.jpg?resize=240%2C278" /></a></p>\n<p>There are a few instances where the result I&#8217;m looking for is nowhere to be found. For example, if I search for <strong>WPWeekly Episode 10</strong> I see most of the episodes in the 100-110 range when I&#8217;m really looking for episode 10. When disabling the plugin, the search results are roughly equal. Both end up not returning the WPWeekly Episode 10 post as the first result. Using the search built into WordPress, I end up having to browse to the last page of search results to find the post I was looking for. With Swiftype, there is a huge improvement as the post shows up as the 13th result. It&#8217;s not number 1 but it&#8217;s not the last page of results either.</p>\n<p>If I wanted to, I could navigate to the Swiftype dashboard and manually move the results around so that episode 10 <strong>IS</strong> the first result. But, what I don&#8217;t understand is why episode 100-110 were displaying if my search string only contained two numbers? I love the ability to rearrange results but if I have to spend a lot of my time rearranging things, then Swiftype is not doing its job.</p>\n<p>There is one last small issue I had. For some reason, the drop down suggestion box didn&#8217;t work for every search query. For example, if I searched for the term <strong>jeopardy</strong> which I already know exist within the post content of an article, the suggestion box doesn&#8217;t show up but the article that contained the word jeopardy within the content ends up being the first result. I reached out to Swiftype to see if they could explain this behaviour to me and this is what they had to say:</p>\n<blockquote><p>Autocomplete suggestions are based on the post title, author name, and tags. Longer text fields like the post body and excerpt are used for full-text searches only (i.e., when the user submits a search). We have implemented it this way because the large volume of text in posts would make the autocomplete results less useful.</p>\n<p>You can read more about the fields we index in this tutorial: <a href="https://swiftype.com/documentation/tutorials/customizing_wordpress_search">https://swiftype.com/documentation/tutorials/customizing_wordpress_search</a></p></blockquote>\n<p>Makes sense to me. I also discovered that I misspelled jeopardy when I added it as a tag to the post. Once I fixed the tag, everything worked as it should.</p>\n<h2>Conclusion:</h2>\n<p>Swiftype was a breeze to set up and within 10 minutes, I was able to improve the search results on my site. It only took that long because of the synchronization process. I&#8217;m going to stick with this plugin/service until I find something better but I come away from this experience being able to recommend Swiftype to those who want to substantially improve the built-in search functionality of WordPress. It&#8217;s also encouraging to know that on this journey I&#8217;ve been on, I&#8217;ve discovered that you don&#8217;t have to pay any money to improve the WordPress search.</p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/review-of-wp-elasticsearch-plugin" rel="bookmark" title="Review Of WP-ElasticSearch Plugin">Review Of WP-ElasticSearch Plugin</a></li>\n<li><a href="http://www.wptavern.com/improving-the-wordpress-search-engine-with-relevanssi" rel="bookmark" title="Improving The WordPress Search Engine With Relevanssi">Improving The WordPress Search Engine With Relevanssi</a></li>\n<li><a href="http://www.wptavern.com/plugin-review-spots-by-interconnectit" rel="bookmark" title="Plugin Review &#8211; Spots By Interconnect/it">Plugin Review &#8211; Spots By Interconnect/it</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/i4oANGpafnI" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 23 May 2013 16:53:12 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:27;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:102:"WordPress.tv: Russell Fair: “I Don’t Know Nothin’ ‘Bout Birthin’ Babies”, er, Child Themes";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19169";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:99:"http://wordpress.tv/2013/05/23/russell-fair-i-dont-know-nothin-bout-birthin-babies-er-child-themes/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:758:"<div id="v-VtACAncc-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19169/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19169/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19169&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/23/russell-fair-i-dont-know-nothin-bout-birthin-babies-er-child-themes/"><img alt="Russell Fair: &#8220;I Don&#8217;t Know Nothin&#8217; &#8216;Bout Birthin&#8217; Babies&#8221;, er, Child Themes" src="http://videos.videopress.com/VtACAncc/video-64768b98f3_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 23 May 2013 14:56:36 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:28;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:29:"WPTavern: WordPress Nostalgia";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7079";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:81:"http://feedproxy.google.com/~r/WordpressTavern/~3/umlgyjF8rs8/wordpress-nostalgia";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:5412:"<p>As we inch closer towards the 10 year anniversary of WordPress, I&#8217;ve been browsing through a few different time capsule posts. Some of them really tap into my nostalgic center while others have me asking questions such as, what ever happened to the Flock browser that WordPress was excited about in 2005? It was described as being just like FireFox but with goodies. If memory serves me right, it was supposed to be a social browser. At any rate, here is a collection of memory lane posts related to WordPress.</p>\n<p><a href="http://www.wptavern.com/down-memory-lane-with-wordpress-com">Down Memory Lane With WordPress.com</a> &#8211; Although this was published in 2009, it gives a great overview of the history of the WordPress.com front page over the years. It&#8217;s filled with interesting tidbits such as when the WordPress.com website promoted the Flock browser. </p>\n<p><a href="http://wplift.com/nostalgia-how-wordpress-websites-used-to-look">Then &#038; Now: How WordPress Companies Have Looked Over the Years</a> &#8211; Published at the end of 2012, not only does this article chronicle the WordPress.org website but a handful of other notable sites as well such as Woothemes, StudioPress and ColorLabs. </p>\n<p><a href="http://wpmu.org/wordpress-10-years-old-visual-history">A 10 Year Visual History of WordPress.org</a> &#8211; While I created a comprehensive history of the WordPress.com domain, Joe Foley of WPMU.org published a visual history of the WordPress.org website which covers all 10 years the website has been around. </p>\n<p><a href="http://planetozh.com/blog/2008/12/a-journey-through-five-years-of-wordpress-interface/">A Journey Through Five Years of WordPress Interface.</a> &#8211; Published in 2008, Ozh compiled a number of screenshots together showcasing the changes that the WordPress interface has gone through since 0.7.1 to 2.7. Take note of WordPress 2.5 as many consider it one of the worst interface redesigns WordPress has been put through. </p>\n<p><a href="http://wplift.com/a-history-of-default-wordpress-themes">A History of Default WordPress Themes</a> &#8211; WPLift also published a history of the default themes that have shipped with WordPress. Although these were far and few between, starting with TwentyTen, we can expect to see a new default theme every year. </p>\n<p><a href="http://es.slideshare.net/chipbennett/wordcamp-kc-the-wordpress-theme-repository">Brief History Of The Theme Repository</a> &#8211; These slides are from Chip Bennett&#8217;s presentation at WordCamp Kansas City that delves into the brief history of the WordPress theme repository. </p>\n<h2>WordPress Archive Project:</h2>\n<p>While compiling this list of posts, I had a <a href="https://twitter.com/wptavern/statuses/337257655884214272">conversation on Twitter</a> with a number of folks discussing the history of WordPress and how it would be cool if we could take various elements of WordPress and create a visual history such as the Login screen or the Post Writing interface. I was told by Siobhan McKeown that she is sort of working on a project like this. She currently has every version of WordPress installed on a local machine in order to create screenshots from one version to the next. It will be interesting to see where this goes. </p>\n<p>Bryan Witherwax or <a href="https://twitter.com/tweeterwax">@Tweeterwax</a> notified me that their WordPress 10 year anniversary party in Seattle, WA will have a local host setup with every version of WordPress installed so that attendees can see for themselves just how far WordPress has progressed. </p>\n<blockquote class="twitter-tweet"><p>@<a href="https://twitter.com/wptavern">wptavern</a> We have some guys setting up all of the versions of WP on a local host for people to play with for our WP 10yr party in Seattle.</p>\n<p>&mdash; Bryan Witherwax (@tweeterwax) <a href="https://twitter.com/tweeterwax/status/337261132622491648">May 22, 2013</a></p></blockquote>\n<p></p>\n<p>Ryan Hellyer has put together a section of his website that shows off the <a href="http://historic-wordpress.ryanhellyer.net/1.0/create-new.html">WordPress 1.0 Post Writing screen</a> as well as the <a href="http://historic-wordpress.ryanhellyer.net/1.0/home-page.html">index page</a> right after WordPress 1.0 is installed. In the coming days/weeks, Ryan will be adding different versions of WordPress with static Administration and index pages so we can at least get an idea of what the workflow is like. If you don&#8217;t see anything, it&#8217;s because the changes have yet to propagate to your DNS server.</p>\n<p>I&#8217;m also going working on a post that explains what steps to go through to install each WordPress version onto a local host. It&#8217;s actually more difficult than you would think, especially for WordPress 0.7.1 which requires it&#8217;s own unique PHP.ini file. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/the-history-of-wordpress-default-themes" rel="bookmark" title="The History Of WordPress Default Themes">The History Of WordPress Default Themes</a></li>\n<li><a href="http://www.wptavern.com/post-format-history-and-wordpress-3-6" rel="bookmark" title="Post Format History And WordPress 3.6">Post Format History And WordPress 3.6</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/umlgyjF8rs8" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 22 May 2013 19:35:31 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:29;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:76:"WordPress.tv: James Banks: Mobile First Development and Design for WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19283";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:93:"http://wordpress.tv/2013/05/22/james-banks-mobile-first-development-and-design-for-wordpress/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:702:"<div id="v-1UpamxO7-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19283/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19283/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19283&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/22/james-banks-mobile-first-development-and-design-for-wordpress/"><img alt="James Banks: Mobile First Development and Design for WordPress" src="http://videos.videopress.com/1UpamxO7/video-7e4a6a670c_std.original.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 22 May 2013 13:22:28 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:30;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:43:"WPTavern: Help iThemes Help Their Neighbors";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7073";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:95:"http://feedproxy.google.com/~r/WordpressTavern/~3/OeENyG5J5qs/help-ithemes-help-their-neighbors";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1148:"<p>iThemes, the company behind products such as BackupBuddy and the Builder theme <a href="http://ithemes.com/2013/05/21/how-you-can-help-oklahoma/">are reporting</a> that their headquarters as well as all of their staff are ok following the Tornadoes that ripped Moore, Oklahoma apart on May 20th. Not only has their company donated $2,000.00 to the Red Cross for relief efforts, but they are asking everyone to consider texting <strong>REDCROSS</strong> to <strong>90999</strong> which will donate <strong>$10.00</strong> to the Red Cross to help support tornado relief efforts in Oklahoma.</p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/ithemes-responds-to-speculation-all-is-well" rel="bookmark" title="iThemes Responds To Speculation &#8211; All Is Well">iThemes Responds To Speculation &#8211; All Is Well</a></li>\n<li><a href="http://www.wptavern.com/review-of-ithemes-builder-theme" rel="bookmark" title="Review Of iThemes Builder Theme">Review Of iThemes Builder Theme</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/OeENyG5J5qs" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 21 May 2013 19:23:05 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:31;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:47:"WPTavern: User Guide – How To Choose A Plugin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7016";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:95:"http://feedproxy.google.com/~r/WordpressTavern/~3/60XdX6380Vo/user-guide-how-to-choose-a-plugin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:14673:"<p>One of the best things about WordPress is its third-party ecosystem of themes and plugins. If WordPress doesn&#8217;t have the feature set you need out of the box, chances are very good that with just a few plugins, you can make the WordPress of your dreams. However, to new and veteran users alike, choosing which plugins to install is not always an easy task. Using this guide as a checklist ought to remove some of the challenges associated with choosing plugins. I&#8217;m not guaranteeing that you&#8217;ll be able to pick the right plugins 100% of the time but by taking these factors into account before making a decision, your chances of success will substantially increase.</p>\n<h2>Factors To Consider:</h2>\n<p><strong>Starting Point</strong> &#8211; On the left hand side of the Plugin repository are a series of links for extending WordPress. I highly suggest starting off with browsing through the Most Popular and Highest Rated plugins first, then move on to other options. The plugins within those two categories have stood the test of time and generally, have earned those positions.</p>\n<p><strong>Requirements</strong> &#8211; The minimum requirements information is supplied directly from the plugin author and is generally used as the first factor in determining whether or not a plugin will work with a specific site. The number of downloads can be used to determine the age of a plugin as well as it&#8217;s popularity.</p>\n<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginRequirements.jpg" rel="thumbnail"><img class="aligncenter size-full wp-image-7063" alt="PluginRequirements" src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginRequirements.jpg?resize=143%2C94" /></a></p>\n<p><strong>Ratings</strong> &#8211; Ratings are based on 5 stars where the average rating is shown at the top. Plugins can only be rated by logged in users. One of the recent changes to the plugin repository are plugin reviews. If you click on each star link, you can read all the reviews that go with that rating, very similar to Amazon.com. When choosing a plugin, don&#8217;t just read the 5 star reviews, also read the 1 and 2 star reviews to get a balanced perspective.</p>\n<p><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginRatings.jpg" rel="thumbnail"><img class="aligncenter size-full wp-image-7064" alt="Plugin Ratings" src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginRatings.jpg?resize=306%2C218" /></a></p>\n<p><strong>Plugin Author</strong> &#8211; Sometimes, the plugin authors name will show up as a link. This link will take you to their WordPress.org profile that displays an overview of their earlier works in the plugin repository as well as a stream of their recent activity. This information can be used as an indicator on their recent development activity around their plugins.</p>\n<p><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginAuthor.jpg" rel="thumbnail"><img class="aligncenter size-full wp-image-7066" alt="PluginAuthor" src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginAuthor.jpg?resize=183%2C118" /></a></p>\n<p><strong>Plugin Support</strong> &#8211; This area of the page shows you how many support questions have been asked in the forum specifically for that plugin. When viewing the plugin support forum, look for the number of threads that have <strong>[resolved]</strong> in the title, the plugin authors name as being the last poster and threads that have answers by someone other than the plugin author which is a sign of a healthy community surrounding the plugin.</p>\n<p><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginSupport.jpg" rel="thumbnail"><img class="aligncenter size-full wp-image-7065" alt="Plugin Support" src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginSupport.jpg?resize=226%2C153" /></a></p>\n<p><strong>Compatibility</strong> &#8211; This area of a plugin page describes whether or not a specific version of a plugin works with the current, or earlier versions of WordPress. Using the drop down boxes, you can select an earlier version of WordPress as well as an earlier version of the plugin to see if enough people in the community have reported on whether they work together or not. This information is based on community feedback, not by the plugin author.</p>\n<p><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginCompatibility.jpg" rel="thumbnail"><img class="aligncenter size-full wp-image-7068" alt="Plugin Compatibility" src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/PluginCompatibility.jpg?resize=233%2C217" /></a></p>\n<p><strong>Trustworthiness</strong> &#8211; Although this is not a consideration you can search for, downloading a plugin from the WordPress plugin repository does have its benefits. Before each plugin is allowed to be hosted on the repository, it must go through a manual screening process that checks things like obfuscated code, malware, spam links, and security. This is also the same process a plugin update must go through before it&#8217;s also published to the repository to make sure nothing malicious is added after the first screening. For these reasons, I can&#8217;t stress enough how important it is to download from the official repository versus somewhere else. That&#8217;s not to say that plugins hosted elsewhere are not equally or more thoroughly screened, but with WordPress.org, you know what you&#8217;re getting.</p>\n<h2>The Big Picture:</h2>\n<p>With over 25,000 plugins in the repository, it&#8217;s becoming increasingly difficult to wade through them all to find the one that perfectly matches functionality with security, support, and reliability. For example, if you were to do a search for Backup or SEO, you&#8217;ll be greeted with a ton of different options. Using the factors I&#8217;ve listed is this guide can substantially increase the odds that a plugin will work out of the box with little hassle. WPTavern.com uses about 25-29 plugins and most of them have been in use for over 4 years, with little to no trouble.</p>\n<h2>Advice From Other WordPress Faithful:</h2>\n<p>I reached out to a couple of people in the WordPress community that deal with the plugin repository on a routine basis either for their own interest or because they are in the business of working with clients. Here is their advice.</p>\n<p><strong>Al Davis of <a title="WPTeach.com" href="http://WPTeach.com">WPTeach.com</a></strong> &#8211; Check what version the plugin is compatible to, as this is a great indicator as to whether the plugin is still being actively developed. If you are unsure how the plugin is going to work on your site, browse through the support forums, see what kinds of issues others may be having and see if those issues are being addressed. Finally, have a look at the screenshots and FAQ if they are available and make sure the plugin actually does what you are looking for.</p>\n<p><strong><a href="http://angiemeekerdesigns.com/">Angie Meeker</a>, Organizer Of WordCamp Columbus and WordPress Consultant</strong> &#8211; My first piece of advice is to ask yourself (and your trusted WordPress adviser or the WP Support Forums), &#8220;<em>Do I really need a plugin for this?</em>&#8221; Many new users to WP are unfamiliar with some of its simplest built-in functions (ones you don&#8217;t even need to know how to code to use). They go searching for a simple gallery plugin, not knowing there&#8217;s one built into the Media Uploader. They search for a plugin to schedule posts, to password protect pages, or to post by email.</p>\n<p><strong>On finding what you want in the first place:</strong><br />\n<strong>1.</strong> Search with as specific of terms as you can think of. &#8220;<em>Rotating Image Galleries</em>&#8221; is a better search than just &#8220;<em>Image Galleries.</em>&#8221; Of course, this is true with all search.</p>\n<p><strong>2.</strong> Google &#8220;<em>what you want to do + plugin + wordpress</em>&#8220;, and look only at search results in the repository (those with wordpress.org/extend/plugins/ in the url). I find that sometimes searching the repository from within is limiting.</p>\n<p><strong>Once you&#8217;ve found one:</strong><br />\n<strong>1.</strong> Read the entire description, Installation, FAQ, and Other Notes (<strong>ALL</strong> of them). If there are Screenshots, look at them to get a hint of what the plugin does. Not all plugins have all of these areas completed, though.</p>\n<p><strong>2.</strong> Look at the &#8220;<em>Requires Version X.X</em>&#8221; and <em>Compatible to X.X</em>&#8221; If your installation is WordPress 3.1, and the plugin requires 3.5, then it&#8217;s <strong>NOT</strong> the plugin author&#8217;s fault when you install it and it doesn&#8217;t work. Either upgrade your WP install, or don&#8217;t use the plugin. If you&#8217;re using 3.5 but the plugin says it&#8217;s only compatible to 3.1, then there&#8217;s no guarantee it will work with that forward version. It <strong>MIGHT</strong>, but there&#8217;s no guarantee.</p>\n<p>Sometimes, a plugin author knows for <strong>CERTAIN</strong> a plugin <strong>DOESN&#8217;T</strong> work with a newer version, and they&#8217;ll make a note of it in the description. Remember, the authors of these plugins are not paid to create and update these, so if a plugin is not up-to-date, don&#8217;t go berserk on the plugin author. Be polite and ask if/when there might be an update.</p>\n<p><strong>3.</strong> Perhaps one of the most useful things you can check out: the Support Forums for a plugin. Plugin authors don&#8217;t <strong>HAVE</strong> to give support for plugins in the repository, but many do. Look at the support threads submitted. How many people submitted the same questions? Does it seem like those questions are simply user error (like maybe they didn&#8217;t read the instructions?) or are they asking about a bug or a problem with the plugin? If there are bugs, is the author responsive to correcting them or providing hints at how users can make corrections? Does the author respond to questions? In my opinion, these point to a plugin author who is vested in the success of his/her plugin, and that usually equals success for you when using it.</p>\n<p><strong>4.</strong> Reviews: These are a recent addition to the WP Plugin Repository, so don&#8217;t be surprised if many plugins don&#8217;t have many or any.</p>\n<p><strong>5.</strong> Lastly, clicking on the plugin author&#8217;s name will take you to a list of all the plugins that author has submitted to the repo. It stands to reason that a plugin author whose overall portfolio has quality ratings, good reviews, maintains the support forums for his/her plugins and keeps the plugins up-to-date probably creates plugins the community can trust.</p>\n<p><strong>Marcus Couch co-host of the <a href="http://wppluginsatoz.com/">WordPress Plugins A-Z Podcast</a> also has some bullet points worth checking</strong></p>\n<p><b>1) How long has the plugin been around? What is the update cycle?</b><br />\nNothing is worse than committing to a particular plugin and having the developer drop support after just a few version revisions. An active developer assures you that the plugin will receive update attention throughout the various WordPress Core updates that come along several times a year. A developer that frequently updates along with WordPress versions is a quality to look for when choosing between plugins to install on your live sites.<br />\n<b><br />\n2) Does this plugin play well with the rest of my plugins?</b><br />\nIf you&#8217;ve ever owned an aquarium, you know that some fish don&#8217;t play well with others, often leading to complete breakdown of the natural order and balance of the tank. Plugins are the same way! Make sure that the plugin you are going to install does not &#8220;overlap&#8221; functionality and cause issues in the performance of others.</p>\n<p><b>3) Plugin vs Plugin Race</b><br />\nIf two plugins exist that perform essentially the same function, install them both but activate only one. Run a site load comparison with sites like Pingdom.com and other data load measurement tools. Find out which plugin is more efficient with loading time and use the results to make a determination if one of the plugins takes too long to load or drains too much system memory.</p>\n<p><b>4) Shortcode Dependency</b><br />\nWhen deciding to use a plugin that relies on shortcodes, understand that somewhere down the line you might want to remove that plugin. This means that there could potentially be thousands of instances of [shortcode] throughout your page and post content.</p>\n<p><b>5) Community</b><br />\nIs there a great community behind the plugin? There are so few plugins with thriving, rabid communities, but it&#8217;s always a huge bonus when a large base of plugin fans can gather with the developer and help to improve a plugin and it&#8217;s core functionality. Once you start using a plugin on a regular basis and find that there is an active community associated with it, PARTICIPATE! I&#8217;ve had many plugins programmed with exactly the functions that I needed simply because I asked the developer to include them in future revisions.</p>\n<h2>Summary:</h2>\n<p>I realize that some of the information in this post is redundant but Angie provides real-world expectations and views. <a href="http://coffee2code.com/">Scott Reilly</a> clearly sums everything up into one paragraph.</p>\n<blockquote><p>When choosing an appropriate plugin from the Plugins Directory it&#8217;s often best to take various factors into consideration rather than just any single factor. The plugin author, the number of support threads replied to in the past two months, the nature of the types of support threads being created (and the nature of the author&#8217;s responses, if any), the number and nature of the reviews being given (or lack thereof), the last update date, and the rating can all play a factor in making a decision.</p></blockquote>\n<p>If you can contribute anything else to this guide for choosing which plugins to install, please do so in the comments.</p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/improving-the-wordpress-search-engine-with-relevanssi" rel="bookmark" title="Improving The WordPress Search Engine With Relevanssi">Improving The WordPress Search Engine With Relevanssi</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/60XdX6380Vo" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 21 May 2013 18:44:06 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:32;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:78:"WordPress.tv: Tom McFarlin: A Discussion and Introduction To WordPress Plugins";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19270";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:95:"http://wordpress.tv/2013/05/21/tom-mcfarlin-a-discussion-and-introduction-to-wordpress-plugins/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:712:"<div id="v-iB45T0OP-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19270/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19270/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19270&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/21/tom-mcfarlin-a-discussion-and-introduction-to-wordpress-plugins/"><img alt="Tom McFarlin: A Discussion and Introduction To WordPress Plugins" src="http://videos.videopress.com/iB45T0OP/video-74b143ddf9_scruberthumbnail_0.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 21 May 2013 14:53:26 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:33;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:77:"WordPress.tv: Dan Petrovic: 10 Ways to Screw Up in Google & 10 Ways to Fix It";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19290";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:92:"http://wordpress.tv/2013/05/21/dan-petrovic-10-ways-to-screw-up-in-google-10-ways-to-fix-it/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:708:"<div id="v-OcYVpVtk-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19290/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19290/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19290&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/21/dan-petrovic-10-ways-to-screw-up-in-google-10-ways-to-fix-it/"><img alt="Dan Petrovic: 10 Ways to Screw Up in Google & 10 Ways to Fix It" src="http://videos.videopress.com/OcYVpVtk/video-443a04dbee_scruberthumbnail_2.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 21 May 2013 13:21:18 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:34;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:62:"WPTavern: Improve The Documentation Efforts By Taking A Survey";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7028";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:114:"http://feedproxy.google.com/~r/WordpressTavern/~3/xq8KNVLJi9M/improve-the-documentation-efforts-by-taking-a-survey";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3226:"<p><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/codex.jpg" rel="thumbnail"><img src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/codex.jpg?resize=165%2C92" alt="Codex" class="alignright size-full wp-image-7029" /></a>In an effort to figure out where resources should be applied to improve the documentation efforts of the WordPress project, there is an <a href="http://wordpressdotorg.polldaddy.com/s/documentation-survey">open survey</a> that will be ongoing for the next few weeks. The survey is composed of 12, easy to answer questions which shouldn&#8217;t take longer than 5 minutes to answer. Along with this survey, there have been renewed efforts by a handful of people to get the various documentation projects up to date. To keep tabs on everything going on documentation wise for the WordPress project, you should subscribe to the <a href="http://make.wordpress.org/docs/">Make WordPress Documentation website</a>. </p>\n<p>Speaking of documentation, how many of you have actually changed something on the <a href="http://codex.wordpress.org/Main_Page">Codex</a> whether it be a typo, a bad link, or corrected information? I&#8217;ve made at least a few changes, such as typos and fixed a couple of broken links but nothing major. Just like many other aspects of the project, documentation is one of those thankless jobs. You can log into the Codex, make some changes and unless you brag about them, no one will ever know. However, documentation is one aspect of the project that impacts users for generations. While correcting a link or adding a paragraph of information is not critical to the Codex, it does provide a warm fuzzy feeling when you think about how many people may come across a page that you fixed so that instead of loading a 404 page which doesn&#8217;t help anyone, they get the information they were looking for. </p>\n<p>Just for fun, I asked <a href="https://twitter.com/wptavern">my twitter followers</a> to tell me in 140 characters or less, why documentation is important to WordPress. This was one of their responses. </p>\n<blockquote class="twitter-tweet"><p>@<a href="https://twitter.com/wptavern">wptavern</a> Same reason documentation is important to anything: so people will know how to use it.</p>\n<p>&mdash; Sallie Goetsch (@salliegoetsch) <a href="https://twitter.com/salliegoetsch/status/336495022709022721">May 20, 2013</a></p></blockquote>\n<p></p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/do-you-think-the-codex-is-the-future-of-documentation-for-wordpress" rel="bookmark" title="Do You Think The Codex Is The Future Of Documentation For WordPress?">Do You Think The Codex Is The Future Of Documentation For WordPress?</a></li>\n<li><a href="http://www.wptavern.com/searching-only-the-codex" rel="bookmark" title="Searching Only The Codex">Searching Only The Codex</a></li>\n<li><a href="http://www.wptavern.com/docs-team-needs-your-help-for-wordpress-3-5" rel="bookmark" title="Docs Team Needs Your Help For WordPress 3.5">Docs Team Needs Your Help For WordPress 3.5</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/xq8KNVLJi9M" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Tue, 21 May 2013 12:40:08 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:35;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:45:"WPTavern: Secrets Revealed: WLTC and WPTavern";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7052";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:96:"http://feedproxy.google.com/~r/WordpressTavern/~3/p6yVX84z_sg/secrets-revealed-wltc-and-wptavern";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3199:"<div class="wp-caption alignright"><img alt="" src="http://i1.wp.com/s.ma.tt/files/2008/03/mat_3582.jpg?w=260" width="260" height="173" /><p class="wp-caption-text">A picture I took at WordCamp Dallas 2008.</p></div>\n<p>There has been a lot of speculation on the &#8220;shady mystery buyer&#8221; of <a href="http://weblogtoolscollection.com/">Weblogs Tools Collection</a> and <a href="http://wptavern.com/">WPTavern</a> (here), which has been funny to watch. It&#8217;s <a href="http://ma.tt/">me</a>.</p>\n<p>Why on earth? Well, it&#8217;s the same and different for each one. Jeff wanted to step back from WPTavern and had an offer but I thought it wasn&#8217;t really fair given the years and effort he had put into the blog. Even if he wasn&#8217;t going to be part of the WordPress world anymore I wanted him to go out of it with the best deal possible. For <a href="http://about.me/mghosh">Mark</a>, the context was similar except I don&#8217;t think he talked to any other buyers because his priority was having it in good hands &#8211; someone who would keep it around. I have a high regard for the great historical context WLTC provided, being there with WordPress from pretty much day one. So each was purchased by <a href="http://audrey.co/">Audrey</a> and went into hibernation.</p>\n<p>Neither was done to be a business or make any money and there are no plans for ads or sponsors on either site.</p>\n<div class="wp-caption alignleft"><img alt="" src="http://i2.wp.com/s.ma.tt/files/2008/03/mat_3499.jpg?w=260" width="260" height="391" /><p class="wp-caption-text">In 2008 when I also first met Mark.</p></div>\n<p>Why haven&#8217;t I posted anything until now? Well, I&#8217;ve been very busy &#8212; Automattic, WordPress, et al. Also the original plan was to just archive them both.</p>\n<p>Convinced by <a href="http://coffee2code.com/">Scott,</a> I reached out to see if Jeff would be interested at taking another crack at making a <a href="http://www.slate.com/articles/news_and_politics/press_box/2010/08/who_said_it_first.html">first rough draft of history</a> for the WordPress world. I recall fondly the days when I used to be more nervous about doing an interview with Jeff than the NY Times because I knew he&#8217;d have much more in-depth and nuanced questions given his deep understanding of WP. I&#8217;m looking forward to seeing that again in the WP blogosphere.</p>\n<p>What&#8217;s the plan? Currently: put WLTC into archive mode, and reboot Tavern to be a &#8220;third place&#8221; for the WP community. We&#8217;ll show off the latest and greatest with <a href="http://bbpress.org/">bbPress</a> and some newer WP features like post formats. Longer term it might make sense to roll Jeff&#8217;s (and anyone else who is interested) work into some official news resource WP.org, but haven&#8217;t really decided anything there yet. Consider this a grand experiment which I&#8217;m as interested to see the results of as I&#8217;m sure you guys are.</p>\n<p>Any questions I could answer?</p>\n<div class="yarpp-related-rss yarpp-related-none">\n<p>No related posts.</p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/p6yVX84z_sg" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 20 May 2013 23:51:08 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:14:"Matt Mullenweg";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:36;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:78:"WPTavern: UI Enhancement Suggestion – Visual Cue For Media Library Searching";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7041";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:126:"http://feedproxy.google.com/~r/WordpressTavern/~3/ExwWeuHfwjg/ui-enhancement-suggestion-visual-cue-for-media-library-searching";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2223:"<p>I have a suggestion for WordPress 3.7 that I believe is a UI element to the media library. I have a number of images within the media library. When I do a search for a specific image e.g. <strong>Codex</strong> which I know is the exact file name, the search is performed with no sign that anything is actually happening. Sometimes, it takes so long for any images to show up that I start running scenarios through my mind such as I broke the site or it can&#8217;t find any images. Then, suddenly, the search results pop up. So I&#8217;m requesting that a spinning circle or other visual cue be displayed when a media search is taking place. It&#8217;s better to know that something is happening versus looking at a blank page that gives the user no clue as to what&#8217;s going on. </p>\n<div id="attachment_7043" class="wp-caption aligncenter"><a href="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/MediaLibrarySearchResults1.jpg" rel="thumbnail"><img src="http://i0.wp.com/www.wptavern.com/wp-content/uploads/2013/05/MediaLibrarySearchResults1.jpg?resize=369%2C230" alt="Media Library Search Results" class="size-full wp-image-7043" /></a><p class="wp-caption-text">Is it searching or is the site broke?</p></div>\n<p>I was pointed in the direction of <a href="http://core.trac.wordpress.org/ticket/22754">Ticket 22754</a> as being related but I don&#8217;t think so. If anyone comes across a ticket where this is already being addressed, please share it in the comments. I searched through Trac myself and came up empty. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/use-the-media-library-or-hand-code" rel="bookmark" title="Use The Media Library Or Hand Code?">Use The Media Library Or Hand Code?</a></li>\n<li><a href="http://www.wptavern.com/media-management-in-wordpress-29" rel="bookmark" title="Media Management In WordPress 2.9">Media Management In WordPress 2.9</a></li>\n<li><a href="http://www.wptavern.com/michael-fields-media-wishlist" rel="bookmark" title="Michael Fields Media Wishlist">Michael Fields Media Wishlist</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/ExwWeuHfwjg" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 20 May 2013 17:06:25 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:37;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:58:"WPTavern: Local 10th Anniversary WordPress Party Next Week";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7038";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:110:"http://feedproxy.google.com/~r/WordpressTavern/~3/7Aj6DhnDJ6I/local-10th-anniversary-wordpress-party-next-week";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1452:"<p>If you live in the Northern Ohio area, make plans to stop by <a href="http://www.waterstreettavern.com/">Water Street Tavern</a> in Kent, OH Saturday, May 25th from 7PM-10PM to help us celebrate the 10th anniversary of WordPress. There will be a cash bar, good food and from what I&#8217;ve read, there might actually be some WordPress swag. This event is an excellent opportunity to wear the <a href="http://hellomerch.com/collections/wordpress/products/wordpress-10th-anniversary-t-shirt">special 10th anniversary t-shirt</a>. </p>\n<p>If you don&#8217;t live in Northern Ohio, check out the following <a href="http://www.meetup.com/WordPress/?see_all=1">list of WordPress parties</a> taking place this weekend to see if one is happening near you. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/10-year-anniversary-project-entry" rel="bookmark" title="10 Year Anniversary Project Entry">10 Year Anniversary Project Entry</a></li>\n<li><a href="http://www.wptavern.com/ohio-wordpress-meetup-april-23rd" rel="bookmark" title="Ohio WordPress Meetup April 23rd">Ohio WordPress Meetup April 23rd</a></li>\n<li><a href="http://www.wptavern.com/first-wordpress-weekly-listening-party" rel="bookmark" title="First WordPress Weekly Listening Party">First WordPress Weekly Listening Party</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/7Aj6DhnDJ6I" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 20 May 2013 16:15:24 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:38;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:62:"WordPress.tv: Bronson Quick: My WordPress Development Workflow";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19295";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:79:"http://wordpress.tv/2013/05/20/bronson-quick-my-wordpress-development-workflow/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:680:"<div id="v-m0BwrANK-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19295/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19295/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19295&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/20/bronson-quick-my-wordpress-development-workflow/"><img alt="Bronson Quick: My WordPress Development Workflow" src="http://videos.videopress.com/m0BwrANK/video-130f49dcd4_scruberthumbnail_1.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 20 May 2013 14:47:54 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:39;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:78:"WordPress.tv: Piero Bellomo: Creare Temi custom con _s Theme, Bootstrap e LESS";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=17341";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:94:"http://wordpress.tv/2013/05/20/piero-bellomo-creare-temi-custom-con-_s-theme-bootstrap-e-less/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:711:"<div id="v-sFAfc6rT-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/17341/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/17341/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=17341&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/20/piero-bellomo-creare-temi-custom-con-_s-theme-bootstrap-e-less/"><img alt="Piero Bellomo: Creare Temi custom con _s Theme, Bootstrap e LESS" src="http://videos.videopress.com/sFAfc6rT/video-68894fd6e4_scruberthumbnail_1.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 20 May 2013 14:14:02 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:40;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:21:"Matt: On Yahoo-Tumblr";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=42384";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:30:"http://ma.tt/2013/05/yahooblr/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1658:"<p>It now looks pretty certain that <a href="http://allthingsd.com/20130519/yahoo-tumblrs-for-cool-board-approves-1-1-billion-deal/">Yahoo has pulled off a deal to buy Tumblr for 1.1B</a>. The relationship between WordPress and Tumblr has always been pretty friendly: Tumblr&#8217;s own blog used to be on WP, WordPress.com supports Tumblr as a Publicize option alongside Twitter and Facebook, our <a href="http://akismet.com/">Akismet</a> team sends them daily emails of splogs on the service, and there&#8217;s healthy import and export traffic both ways. (Imports have actually spiked on the rumors even though it&#8217;s Sunday: normally we import 400-600 posts an hour from Tumblr, last hour it was over 72,000.)</p>\n<p>News like this, whether from a friend or a competitor, is always bittersweet: I&#8217;m curious to see what the creative folks behind Tumblr do with their new resources, both personal and corporate, but I&#8217;m more interested to know what they would have done over the next 5-10 years as an independent company. I think we&#8217;re at the cusp of understanding the ultimate value of web publishing platforms, particularly ones that work cross-domain, and while Yahoo&#8217;s all-cash deal by some metrics, like revenue, is very generous, I think it&#8217;s a tenth of the value that will be created in these platforms over the coming years.</p>\n<p><ins datetime="2013-05-20T13:26:00+00:00">Update: Some people are reading too much into the import numbers &#8212; I don&#8217;t think there will be an exodus from Tumblr. For more color read the <a href="http://ma.tt/2013/05/yahooblr/#comments">comments on this post</a>.</ins></p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 20 May 2013 03:38:05 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:41;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:57:"WordPress.tv: Joe Ortenzi: Inclusive Design for WordPress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19241";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:74:"http://wordpress.tv/2013/05/19/joe-ortenzi-inclusive-design-for-wordpress/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:670:"<div id="v-4AREivt9-1" class="video-player">\n</div>\n<br />  <a rel="nofollow" href="http://feeds.wordpress.com/1.0/gocomments/wptv.wordpress.com/19241/"><img alt="" border="0" src="http://feeds.wordpress.com/1.0/comments/wptv.wordpress.com/19241/" /></a> <img alt="" border="0" src="http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=19241&subd=wptv&ref=&feed=1" width="1" height="1" /><div><a href="http://wordpress.tv/2013/05/19/joe-ortenzi-inclusive-design-for-wordpress/"><img alt="Joe Ortenzi: Inclusive Design for WordPress" src="http://videos.videopress.com/4AREivt9/video-104406a69d_scruberthumbnail_1.jpg" width="160" height="120" /></a></div>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sun, 19 May 2013 14:05:50 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:12:"WordPress.tv";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:42;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:75:"WordPress.tv: Mikey De Wildt: How to Survive People Discovering Your Plugin";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:28:"http://wordpress.tv/?p=19230";s:7:"attribs";a:0:{}s