se_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:54:"http://ma.tt/2013/05/houston-modern-american-boomtown/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:391:"<p>The Wall Street Journal <a href="http://online.wsj.com/article/SB10001424127887323744604578472873183655916?mg=reno64-wsj.html?dsk=y">interviews Annise Parker on Houston and calls it &#8220;The Modern American Boomtown&#8221;</a>. I think Houston is the most under-appreciated city in North America, as anyone who&#8217;s hung out with me for more than a few hours has heard me preach.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 18 May 2013 13:18:28 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:44;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:24:"Matt: The Physical Graph";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:21:"http://ma.tt/?p=42362";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:40:"http://ma.tt/2013/05/the-physical-graph/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:284:"<p>Wired has a great cover story on <a href="http://audrey.co/">Audrey</a> portfolio company <a href="http://smartthings.com/">SmartThings</a>: <a href="http://www.wired.com/gadgetlab/2013/05/internet-of-things/all/">In the Programmable World, All Our Objects Will Act as One</a>.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 17 May 2013 21:31:03 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:4:"Matt";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:45;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:45:"WPTavern: Code Garage Migrations Are Underway";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7022";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:97:"http://feedproxy.google.com/~r/WordpressTavern/~3/82DyMFQcfXk/code-garage-migrations-are-underway";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3095:"<p><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2012/12/CodeGaragelogo.jpg" rel="thumbnail"><img src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2012/12/CodeGaragelogo.jpg?resize=262%2C54" alt="Code Garage Logo" class="alignright size-full wp-image-6754" /></a>In late 2012, <a href="http://blog.vaultpress.com/2012/12/21/vaultpress-in-the-garage/">VaultPress announced</a> that they had acquired security company Code Garage. At the time, the acquisition seemed like a talent grab more than anything else. Even though <a href="http://blog.vaultpress.com/2012/12/21/vaultpress-in-the-garage/">VaultPress stated</a> that they would continue to work on the Code Garage product, it didn&#8217;t make much sense to have both services. When I <a href="http://www.wptavern.com/automattic-acquires-codegarage">initially reported on the acquisition</a>, I told Code Garage customers to watch the situation closely because at some point, Code Garage was going to close up shop in favor of VaultPress. </p>\n<p>VaultPress has now <a href="http://blog.vaultpress.com/2013/05/15/code-garage-migration/">confirmed</a> that they will be shutting down Code Garage after July 1st. </p>\n<blockquote><p>Today we’re happy to announce a migration plan that provides Code Garage users with the protection they’re used to — while letting us improve security and backup services for everyone by focusing our resources on VaultPress. Through July 1, all Code Garage customers are invited to migrate to VaultPress.  To sweeten the deal, your first two months are on us — you won’t see a charge from Code Garage or VaultPress for two months after the migration.  After those 2 months, your Code Garage bill will remain  unchanged – you’ll keep paying what you’ve been paying as a Code Garage customer.</p>\n<p>If you’re not interested in migrating, we’ll maintain your service at Code Garage through July 1, and give you your last month free.</p></blockquote>\n<p>Any Code Garage customer that migrates to VaultPress will automatically be placed on the VaultPress Lite plan with the addition of daily security scans. For a detailed look at how Code Garage was founded and how Timthumb played a role in the company&#8217;s success, read this <a href="http://codegarage.com/blog/2013/05/codegarage-locker-is-migrating-to-vaultpress/">blog post by founder Peter Butler</a>. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/automattic-acquires-codegarage" rel="bookmark" title="Automattic Acquires CodeGarage">Automattic Acquires CodeGarage</a></li>\n<li><a href="http://www.wptavern.com/a-vaultpress-everyone-can-afford" rel="bookmark" title="A VaultPress Everyone Can Afford">A VaultPress Everyone Can Afford</a></li>\n<li><a href="http://www.wptavern.com/vaultpress-now-supports-wordpress-multisite" rel="bookmark" title="VaultPress Now Supports WordPress Multisite">VaultPress Now Supports WordPress Multisite</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/82DyMFQcfXk" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 17 May 2013 18:58:07 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:46;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:61:"WPTavern: Do You Mistrust A Company That Misspells WordPress?";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7018";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:112:"http://feedproxy.google.com/~r/WordpressTavern/~3/gI-_S7CeGYU/do-you-mistrust-a-company-that-misspells-wordpress";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1848:"<p>As long as I&#8217;ve been involved, I&#8217;ve seen countless numbers of companies misspelling WordPress. Despite the fact that <a href="http://www.wptavern.com/automatically-correcting-the-wordpress-mistake">WordPress added a filter</a> to automatically correct the word, it still happens and when it does, the results are not pretty. Members of the community point out their mistake and while generally it&#8217;s enough to get a good laugh, it&#8217;s usually followed up with &#8220;<em>can&#8217;t trust or work with a company that can&#8217;t even spell the name of the software correctly</em>&#8220;. So after you vote in the poll, let me know in the comments if the spelling of WordPress is an indicator as to whether a company is worth doing business with or not.</p>\n<div class="aligncenter">Note: There is a poll embedded within this post, please visit the site to participate in this post''s poll.</div>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/would-you-take-wordpress-advice-from-a-non-wordpress-using-site" rel="bookmark" title="Would You Take WordPress Advice From A Non WordPress Using Site?">Would You Take WordPress Advice From A Non WordPress Using Site?</a></li>\n<li><a href="http://www.wptavern.com/listener-poll-do-you-think-bbpress-will-evolve-into-a-wordpress-plugin" rel="bookmark" title="Listener Poll: Do You Think bbPress Will Evolve Into A WordPress Plugin?">Listener Poll: Do You Think bbPress Will Evolve Into A WordPress Plugin?</a></li>\n<li><a href="http://www.wptavern.com/automatically-correcting-the-wordpress-mistake" rel="bookmark" title="Automatically Correcting The WordPress Mistake">Automatically Correcting The WordPress Mistake</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/gI-_S7CeGYU" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 17 May 2013 12:45:28 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:47;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:63:"WPTavern: BuddyPress 1.7.2 Released – Contains Security Fixes";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7012";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:111:"http://feedproxy.google.com/~r/WordpressTavern/~3/7lWEbGUXtwo/buddypress-1-7-2-released-contains-security-fixes";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1513:"<p><a href="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2009/04/buddypresslogo.png" rel="thumbnail"><img src="http://i1.wp.com/www.wptavern.com/wp-content/uploads/2009/04/buddypresslogo.png?resize=212%2C76" alt="BuddyPress Logo" class="alignright size-full wp-image-966" /></a><a href="http://buddypress.org/2013/05/buddypress-1-7-2/">BuddyPress 1.7.2</a> was released a little while ago. It contains some bug fixes but the most notable items include several MySQL Injection possibilities that have been patched. 1.7.2 is being classified as a recommended upgrade for anyone using BuddyPress 1.5 or above. </p>\n<p>I&#8217;m keeping tabs on BuddyPress because at some point in the future, this site will be utilizing it combination with bbPress. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/bbpress-2-0-1-released-fixes-anonymous-security-bug" rel="bookmark" title="bbPress 2.0.1 Released &#8211; Fixes Anonymous Security Bug">bbPress 2.0.1 Released &#8211; Fixes Anonymous Security Bug</a></li>\n<li><a href="http://www.wptavern.com/wordpress-2-9-2-released-security-fix" rel="bookmark" title="WordPress 2.9.2 Released &#8211; Security Fix">WordPress 2.9.2 Released &#8211; Security Fix</a></li>\n<li><a href="http://www.wptavern.com/wordpress-2-8-3-released" rel="bookmark" title="WordPress 2.8.3 Released">WordPress 2.8.3 Released</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/7lWEbGUXtwo" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 17 May 2013 01:15:23 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:48;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:52:"WPTavern: Widget Visibility – When Do We Get That?";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://www.wptavern.com/?p=7008";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:99:"http://feedproxy.google.com/~r/WordpressTavern/~3/PzLyOkRSce8/widget-visibility-when-do-we-get-that";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:2325:"<p>WordPress.com users now have a feature available to them that should have been in the core of WordPress a long time ago. They call it, <a href="http://en.blog.wordpress.com/2013/05/15/conditional-widget-visibility/">Widget Visibility</a>. Users can either hide or show widgets based on <strong>category, author, tag, date, or page</strong>. This covers the most common use cases without having a need to use conditional tags. </p>\n<p><a href="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/WidgetVisibility.jpg" rel="thumbnail"><img src="http://i2.wp.com/www.wptavern.com/wp-content/uploads/2013/05/WidgetVisibility.jpg?resize=399%2C189" alt="Widget Visibility " class="aligncenter size-full wp-image-7009" /></a></p>\n<p>The interface is surprisingly simple. In fact, I prefer what WordPress.com is using versus Widget Logic which requires me to know conditional tags. I&#8217;m wondering how did WordPress.com get this feature before stand-alone WordPress? When I asked this question on Twitter, Ian Stewart responded with:</p>\n<blockquote><p>@wptavern I’d look for it here <a href="http://jetpack.me/">http://jetpack.me/</a>  :)</p></blockquote>\n<p>This makes sense and in fact would allow the Jetpack team to get valuable feedback before ever considering putting it into core. If you can&#8217;t wait that long, try out the <a href="http://wordpress.org/extend/plugins/widget-context/">Widget Context plugin</a>. Widget Context provides a similar interface with a few more bells and whistles that the WordPress.com variety doesn&#8217;t have. </p>\n<div class="yarpp-related-rss">\n<p>Related posts:<ol>\n<li><a href="http://www.wptavern.com/feedback-needed-for-new-widget-context-user-interface" rel="bookmark" title="Feedback Needed For New Widget Context User Interface">Feedback Needed For New Widget Context User Interface</a></li>\n<li><a href="http://www.wptavern.com/widget-context-updated" rel="bookmark" title="Widget Context Updated">Widget Context Updated</a></li>\n<li><a href="http://www.wptavern.com/kaspars-adds-widget-context-to-plugin-repository" rel="bookmark" title="Kaspars Adds Widget Context To Plugin Repository">Kaspars Adds Widget Context To Plugin Repository</a></li>\n</ol></p>\n</div>\n<img src="http://feeds.feedburner.com/~r/WordpressTavern/~4/PzLyOkRSce8" height="1" width="1" />";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Fri, 17 May 2013 00:19:36 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:6:"Jeffro";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:49;a:6:{s:4:"data";s:13:"\n	\n	\n	\n	\n	\n	\n";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:28:"BuddyPress: BuddyPress 1.7.2";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:31:"http://buddypress.org/?p=164102";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:47:"http://buddypress.org/2013/05/buddypress-1-7-2/";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:989:"<p>BuddyPress 1.7.2 is now available. This maintenance and security release fixes several MySQL injection possibilities reported by Glyn Wintle from dxw.com, and a few other issues we caught after 1.7.1 was released last month. 1.7.2 is a recommended upgrade for all installations running BP 1.5+.</p>\n<p>For complete details on what&#8217;s changed in BP 1.7.2, see the <a href="http://buddypress.trac.wordpress.org/query?status=closed&group=resolution&milestone=1.7.2">Trac milestone</a> or the <a href="http://codex.buddypress.org/developer/releases/version-1-7-2/">1.7.2 changelog in the BuddyPress Codex</a>.</p>\n<p>Download it today from the <a href="http://wordpress.org/extend/plugins/buddypress/">wordpress.org plugin repository</a>, or from the Plugins page in your WordPress Dashboard. Questions or comments about the release? Visit our <a href="http://buddypress.org/support">support forums</a> or <a href="http://buddypress.trac.wordpress.org">our bugtracker</a>.</p>";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Thu, 16 May 2013 22:00:21 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:17:"John James Jacoby";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}}}}}}}}}}s:4:"type";i:128;s:7:"headers";a:9:{s:6:"server";s:5:"nginx";s:4:"date";s:29:"Wed, 29 May 2013 10:02:03 GMT";s:12:"content-type";s:8:"text/xml";s:14:"content-length";s:6:"133000";s:10:"connection";s:5:"close";s:4:"vary";s:15:"Accept-Encoding";s:13:"last-modified";s:29:"Wed, 29 May 2013 09:45:30 GMT";s:4:"x-nc";s:11:"HIT lax 250";s:13:"accept-ranges";s:5:"bytes";}s:5:"build";s:14:"20111015034325";}', 'no');
